/* ============================================
 * PIXI.JS / CANVAS COLOR UTILITIES
 * Use these for WebGL rendering
 * ============================================ */

/** Convert hex string to number for PixiJS */
export function hexToNumber(hex: string): number {
  return parseInt(hex.replace('#', ''), 16);
}

/** Get task color by type for PixiJS */
export function getTaskColor(type: keyof typeof TASK_COLORS): number {
  return hexToNumber(TASK_COLORS[type].primary);
}

/** Get heatmap color by intensity (0-1) */
export function getHeatmapColor(intensity: number): number {
  const clampedIntensity = Math.max(0, Math.min(1, intensity));

  for (let i = 1; i < HEATMAP_GRADIENT.length; i++) {
    if (clampedIntensity <= HEATMAP_GRADIENT[i].stop) {
      const prev = HEATMAP_GRADIENT[i - 1];
      const curr = HEATMAP_GRADIENT[i];
      const t = (clampedIntensity - prev.stop) / (curr.stop - prev.stop);
      return lerpColor(prev.color, curr.color, t);
    }
  }

  return HEATMAP_GRADIENT[HEATMAP_GRADIENT.length - 1].color;
}

/** Linear interpolation between two colors */
function lerpColor(color1: number, color2: number, t: number): number {
  const r1 = (color1 >> 16) & 0xFF;
  const g1 = (color1 >> 8) & 0xFF;
  const b1 = color1 & 0xFF;

  const r2 = (color2 >> 16) & 0xFF;
  const g2 = (color2 >> 8) & 0xFF;
  const b2 = color2 & 0xFF;

  const r = Math.round(r1 + (r2 - r1) * t);
  const g = Math.round(g1 + (g2 - g1) * t);
  const b = Math.round(b1 + (b2 - b1) * t);

  return (r << 16) | (g << 8) | b;
}

