{
  "project": "mms-fractal-planner",
  "version": "1.0.0-rewrite",
  "description": "High-Performance Train Maintenance Planner (PixiJS + SoA)",
  "harness": {
    "protocol": "anthropic-long-running-agent",
    "reference": "https://www.anthropic.com/engineering/effective-harnesses-for-long-running-agents",
    "mandatoryChecks": {
      "beforeMarkingComplete": [
        "pnpm typecheck",
        "pnpm test --run",
        "pnpm lint",
        "pnpm test:e2e"
      ],
      "sessionStart": [
        "read claude-progress.txt",
        "run ./init.sh",
        "run pnpm typecheck && pnpm test --run && pnpm lint && pnpm test:e2e"
      ]
    },
    "rule": "ALL tests must pass before any feature can be marked as 'done'. No exceptions."
  },
  "stack": {
    "framework": "Vite",
    "ui": ["React 19", "MUI v7"],
    "rendering": "PixiJS v8",
    "state": ["Zustand (UI)", "Zustand Vanilla (Transient)", "TanStack Query"],
    "language": "TypeScript 5.x (Strict)",
    "testing": ["Vitest", "Playwright", "Playwright MCP"],
    "architecture": "Data-Oriented Design (SoA)"
  },
  "phases": {
    "setup-refactor": [
      { "id": "refactor-001", "name": "Remove Astro & Redux dependencies", "status": "done", "passes": true },
      { "id": "refactor-002", "name": "Install TanStack Query & seedrandom", "status": "done", "passes": true },
      { "id": "refactor-003", "name": "Configure Vite SPA mode", "status": "done", "passes": true }
    ],
    "core-engine": [
      { "id": "engine-001", "name": "Implement SoA Data Structures (TypedArrays)", "status": "done", "passes": true },
      { "id": "engine-002", "name": "Deterministic Mock Generator (Seeded)", "status": "done", "passes": true },
      { "id": "engine-003", "name": "Virtual Scroller Logic (Physics/Inertia)", "status": "done", "passes": true },
      { "id": "engine-004", "name": "Coordinate System Transformer (Time <-> Pixels)", "status": "done", "passes": true }
    ],
    "rendering-layers": [
      { "id": "render-001", "name": "PixiJS Stage & Context Integration", "status": "done", "passes": true },
      { "id": "render-002", "name": "LOD 0: Heatmap Fragment Shader", "status": "done", "passes": true },
      { "id": "render-003", "name": "LOD 1: Instanced Mesh for Bars", "status": "done", "passes": true },
      { "id": "render-004", "name": "LOD 2: Capsule Sprites & Text", "status": "done", "passes": true },
      { "id": "render-005", "name": "Hysteresis Zoom Logic", "status": "done", "passes": true }
    ],
    "testing-automation": [
      { "id": "test-001", "name": "Fix Vitest/Playwright separation", "status": "done", "passes": true },
      { "id": "test-002", "name": "Create unit tests for core engine", "status": "done", "passes": true },
      { "id": "test-003", "name": "Configure Playwright MCP for visual testing", "status": "done", "passes": true },
      { "id": "test-004", "name": "Create Harness verification protocol script", "status": "done", "passes": true },
      { "id": "test-005", "name": "Create E2E smoke tests (console error detection)", "status": "done", "passes": true },
      { "id": "test-006", "name": "Fix PixiJS v8 initialization errors", "status": "done", "passes": true },
      { "id": "test-007", "name": "Integrate pre-commit hooks for test validation", "status": "pending", "passes": false }
    ],
    "interaction": [
      { "id": "interact-001", "name": "Transient Drag-and-Drop Controller", "status": "pending", "passes": false },
      { "id": "interact-002", "name": "Collision Detection (Interval Tree)", "status": "pending", "passes": false },
      { "id": "interact-003", "name": "React Overlays (Sidebar/Tooltip)", "status": "pending", "passes": false }
    ]
  }
}

import type { StorybookConfig } from '@storybook/react-vite';

const config: StorybookConfig = {
  stories: ['../src/**/*.mdx', '../src/**/*.stories.@(js|jsx|mjs|ts|tsx)'],
  addons: [
    '@storybook/addon-essentials',
  ],
  framework: {
    name: '@storybook/react-vite',
    options: {},
  },
  docs: {},
  typescript: {
    reactDocgen: 'react-docgen-typescript',
  },
};

export default config;

