  critical: '#E53935',
  bottleneck: '#B71C1C',
} as const;

/** Heatmap gradient stops for shaders */
export const HEATMAP_GRADIENT = [
  { stop: 0.0, color: 0xE3F2FD },  // Very low - light blue
  { stop: 0.2, color: 0x64B5F6 },  // Low-Medium - blue
  { stop: 0.4, color: 0xFFE0B2 },  // Medium - light orange
  { stop: 0.6, color: 0xFFB74D },  // Medium-High - orange
  { stop: 0.8, color: 0xFF9800 },  // High - dark orange
  { stop: 1.0, color: 0xB71C1C },  // Critical - dark red
] as const;

/** Task/Block colors for Gantt and Capsules */
export const TASK_COLORS = {
  mechanical: {
