     1→import { Application, Container, Graphics } from 'pixi.js';
     2→import { getViewportState, subscribeViewport, type ViewportState } from '../engine/store/viewportStore';
     3→import { getSimulationState, subscribeSimulation } from '../engine/store/simulationStore';
     4→import { HeatmapLayer } from './layers/HeatmapLayer';
     5→import { BarsLayer } from './layers/BarsLayer';
     6→import { CapsulesLayer } from './layers/CapsulesLayer';
     7→
     8→/**
     9→ * FractalRenderer - High-performance PixiJS renderer with LOD layers.
    10→ *
    11→ * Manages the PixiJS Application and three distinct rendering layers:
    12→ * - LOD 0: Heatmap (GPU shader-based)
    13→ * - LOD 1: Stacked bars (instanced rendering)
    14→ * - LOD 2: Detailed capsules with text
    15→ *
    16→ * Integrates with Zustand stores for reactive viewport/data updates.
    17→ */
    18→
    19→export interface FractalRendererConfig {
    20→  /** Row height in pixels for train lanes */
    21→  rowHeight: number;
    22→  /** Background color */
    23→  backgroundColor: number;
    24→  /** Enable debug overlay */
    25→  debug: boolean;
    26→}
    27→
    28→const DEFAULT_CONFIG: FractalRendererConfig = {
    29→  rowHeight: 40,
    30→  backgroundColor: 0x1a1a2e,
    31→  debug: false,
    32→};
    33→
    34→export class FractalRenderer {
    35→  private app: Application | null = null;
    36→  private isInitialized = false;
    37→
    38→  /** Layer containers for each LOD */
    39→  private lod0Container: Container | null = null;
    40→  private lod1Container: Container | null = null;
    41→  private lod2Container: Container | null = null;
    42→
    43→  /** Grid overlay for debugging */
    44→  private gridOverlay: Graphics | null = null;
    45→
    46→  /** LOD layer instances */
    47→  private heatmapLayer: HeatmapLayer | null = null;
    48→  private barsLayer: BarsLayer | null = null;
    49→  private capsulesLayer: CapsulesLayer | null = null;
    50→
    51→  /** Store unsubscribe functions */
    52→  private unsubscribeViewport: (() => void) | null = null;
    53→  private unsubscribeSimulation: (() => void) | null = null;
    54→
    55→  /** Render loop state */
    56→  private rafId: number | null = null;
    57→  private needsRender = true;
    58→
    59→  /** Configuration */
    60→  private config: FractalRendererConfig;
    61→
    62→  /** Cache for last viewport state (avoid unnecessary re-renders) */
    63→  private lastViewport: Partial<ViewportState> = {};
    64→
    65→  constructor(config: Partial<FractalRendererConfig> = {}) {
    66→    this.config = { ...DEFAULT_CONFIG, ...config };
    67→  }
    68→
    69→  /**
    70→   * Initialize the PixiJS Application and mount to container.
    71→   */
    72→  async init(container: HTMLElement): Promise<void> {
    73→    if (this.isInitialized) {
    74→      console.warn('FractalRenderer already initialized');
    75→      return;
    76→    }
    77→
    78→    // Get container dimensions before init
    79→    const rect = container.getBoundingClientRect();
    80→    const width = rect.width || 800;
    81→    const height = rect.height || 600;
    82→
    83→    // Create PixiJS Application with WebGL preference
    84→    // Note: Don't use resizeTo during init to avoid render before layers are ready
    85→    this.app = new Application();
    86→
    87→    await this.app.init({
    88→      background: this.config.backgroundColor,
    89→      width,
    90→      height,
    91→      antialias: true,
    92→      resolution: window.devicePixelRatio || 1,
    93→      autoDensity: true,
    94→      powerPreference: 'high-performance',
    95→    });
    96→
    97→    // Append canvas to container
    98→    container.appendChild(this.app.canvas);
    99→
   100→    // Set canvas style for proper sizing
   101→    this.app.canvas.style.width = '100%';
   102→    this.app.canvas.style.height = '100%';
   103→    this.app.canvas.style.display = 'block';
   104→
   105→    // Create layer hierarchy AFTER app is fully initialized
   106→    this.createLayers();
   107→
   108→    // Subscribe to store updates
   109→    this.subscribeToStores();
   110→
   111→    // Update viewport dimensions
   112→    getViewportState().setDimensions(width, height);
   113→
   114→    // Mark as initialized before starting render loop
   115→    this.isInitialized = true;
   116→
   117→    // Start render loop
   118→    this.startRenderLoop();
   119→
   120→    console.log('[FractalRenderer] Initialized', { width, height });
   121→  }
   122→
   123→  /**
   124→   * Create container hierarchy for LOD layers.
   125→   */
   126→  private createLayers(): void {
   127→    if (!this.app) return;
   128→
   129→    // LOD 0: Heatmap layer (bottom)
   130→    this.lod0Container = new Container();
   131→    this.lod0Container.label = 'lod0-heatmap';
   132→    this.app.stage.addChild(this.lod0Container);
   133→
   134→    // Initialize heatmap layer
   135→    this.heatmapLayer = new HeatmapLayer({ rowHeight: this.config.rowHeight });
   136→    this.lod0Container.addChild(this.heatmapLayer.getContainer());
   137→
   138→    // LOD 1: Bars layer (middle)
   139→    this.lod1Container = new Container();
   140→    this.lod1Container.label = 'lod1-bars';
   141→    this.app.stage.addChild(this.lod1Container);
   142→
   143→    // Initialize bars layer
   144→    this.barsLayer = new BarsLayer({ rowHeight: this.config.rowHeight });
   145→    this.lod1Container.addChild(this.barsLayer.getContainer());
   146→
   147→    // LOD 2: Capsules layer (top)
   148→    this.lod2Container = new Container();
   149→    this.lod2Container.label = 'lod2-capsules';
   150→    this.app.stage.addChild(this.lod2Container);
   151→
   152→    // Initialize capsules layer
   153→    this.capsulesLayer = new CapsulesLayer({ rowHeight: this.config.rowHeight });
   154→    this.lod2Container.addChild(this.capsulesLayer.getContainer());
   155→
   156→    // Debug grid overlay (always on top)
   157→    if (this.config.debug) {
   158→      this.gridOverlay = new Graphics();
   159→      this.gridOverlay.label = 'debug-grid';
   160→      this.app.stage.addChild(this.gridOverlay);
   161→    }
   162→  }
   163→
   164→  /**
   165→   * Subscribe to Zustand stores for reactive updates.
   166→   */
   167→  private subscribeToStores(): void {
   168→    // Viewport changes trigger re-render
   169→    this.unsubscribeViewport = subscribeViewport((state) => {
   170→      // Only mark dirty if relevant properties changed
   171→      if (
   172→        state.scale !== this.lastViewport.scale ||
   173→        state.offsetX !== this.lastViewport.offsetX ||
   174→        state.offsetY !== this.lastViewport.offsetY ||
   175→        state.lod !== this.lastViewport.lod
   176→      ) {
   177→        this.lastViewport = {
   178→          scale: state.scale,
   179→          offsetX: state.offsetX,
   180→          offsetY: state.offsetY,
   181→          lod: state.lod,
   182→        };
   183→        this.needsRender = true;
   184→        if (this.heatmapLayer) {
   185→          this.heatmapLayer.markDirty();
   186→        }
   187→        if (this.barsLayer) {
   188→          this.barsLayer.markDirty();
   189→        }
   190→        if (this.capsulesLayer) {
   191→          this.capsulesLayer.markDirty();
   192→        }
   193→      }
   194→    });
   195→
   196→    // Simulation data changes trigger re-render
   197→    this.unsubscribeSimulation = subscribeSimulation(() => {
   198→      this.needsRender = true;
   199→      if (this.heatmapLayer) {
   200→        this.heatmapLayer.markDirty();
   201→      }
   202→      if (this.barsLayer) {
   203→        this.barsLayer.markDirty();
   204→      }
   205→      if (this.capsulesLayer) {
   206→        this.capsulesLayer.markDirty();
   207→      }
   208→    });
   209→  }
   210→
   211→  /**
   212→   * Main render loop using requestAnimationFrame.
   213→   */
   214→  private startRenderLoop(): void {
   215→    const render = (): void => {
   216→      if (!this.isInitialized || !this.app) return;
   217→
   218→      if (this.needsRender) {
   219→        this.render();
   220→        this.needsRender = false;
   221→      }
   222→
   223→      this.rafId = requestAnimationFrame(render);
   224→    };
   225→
   226→    this.rafId = requestAnimationFrame(render);
   227→  }
   228→
   229→  /**
   230→   * Render current frame based on viewport and LOD.
   231→   */
   232→  private render(): void {
   233→    if (!this.app) return;
   234→
   235→    const viewport = getViewportState();
   236→    const simulation = getSimulationState();
   237→
   238→    // Update layer visibility based on LOD
   239→    this.updateLodVisibility(viewport.lod);
   240→
   241→    // Update viewport transform on stage
   242→    this.updateStageTransform(viewport);
   243→
   244→    // Update active LOD layer
   245→    if (viewport.lod === 0 && this.heatmapLayer) {
   246→      this.heatmapLayer.update();
   247→    } else if (viewport.lod === 1 && this.barsLayer) {
   248→      this.barsLayer.update();
   249→    } else if (viewport.lod === 2 && this.capsulesLayer) {
   250→      this.capsulesLayer.update();
   251→    }
   252→
   253→    // Render debug grid if enabled
   254→    if (this.config.debug && this.gridOverlay) {
